// AUTO-GENERATED BY scripts/stage-public.mjs — DO NOT EDIT BY HAND.
// Source of truth: scripts/<name>.mjs in the internal monorepo.
// Path references rewritten so the public repo can be self-contained.

// verify-engine-invariants: structural guard for the statistical engine.
//
// The regression class this gate blocks: a new engine function reads disc
// word signs, builds a phonetic string via `signs.map(phoneticValue).join("-")`,
// then re-syllabifies the string to form bigrams. That round-trip silently
// treats `?17` and `??` as if they were real syllables, defeating the
// adjacency-breaking lacuna policy and inflating bigram counts.
//
// The architectural fix is that every disc-bigram-producing path must
// flow through one of the canonical helpers in comparison.mjs:
//   - `buildPdBigramsFromWords(...)`  (for the headline bigram set)
//   - `extractKnownPdSegments(...)`   (for token / trigram / positional analyses)
//
// This script enforces that invariant by static substring scan. It
// blocks the join+syllabify regression class loudly, in CI, before any
// new code lands. If you have a legitimate reason for a different
// bigram pipeline, document it AND add it to ALLOWED_PIPELINES below.

import { readFileSync, readdirSync } from "node:fs";
import { dirname, join, relative } from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = dirname(fileURLToPath(import.meta.url));
const REPO_ROOT = join(__dirname, "..");
const ENGINE_PATH = join(REPO_ROOT, "app/js/engine/comparison.mjs");
// Sections that render UI cards. Each can also leak the join+syllabify
// regression class if it bypasses the canonical helpers, so the gate scans
// every section file alongside the engine. The section list is auto-discovered
// so adding a new section file automatically extends gate coverage.
const SECTIONS_DIR = join(REPO_ROOT, "app/js/sections");
const SECTION_PATHS = readdirSync(SECTIONS_DIR)
  .filter((f) => f.endsWith(".mjs"))
  .map((f) => join(SECTIONS_DIR, f));
const SCAN_PATHS = [ENGINE_PATH, ...SECTION_PATHS];

// The exact regression class. Any of these patterns indicates a
// function is rebuilding a phonetic string from raw signs and
// re-syllabifying it, instead of going through the canonical helpers.
const BANNED_PATTERNS = [
  {
    re: /\.map\(\s*phoneticValue\s*\)\s*\.join\(\s*["']-["']\s*\)/g,
    why: "join+syllabify chain — use extractKnownPdSegments() instead",
  },
  {
    re: /phoneticValue\([^)]*\)[^;]*\.join\(\s*["']-["']\s*\)\s*\.split/g,
    why: "round-tripping phonetic values through string concat — use extractKnownPdSegments()",
  },
  {
    re: /syllabify\([^)]*\.join\(\s*["']-["']\s*\)/g,
    why: "syllabify of joined phonetic values — use extractKnownPdSegments()",
  },
  {
    // Catches the rasSylFreq-style regression that escapes the simpler
    // patterns: `signs.map(s => valueMap.get(s) ?? ...).join("-")`. Any
    // `.map(...).join("-")` chain co-located on a single line (with at
    // most one level of nested parentheses inside the .map callback) is
    // blocked. Legitimate display sites in comparison.mjs carry inline
    // `canonical-pipeline-allowed` markers on the same line so they remain
    // silenced. New code that needs to bypass this rule must do the same
    // and explain why. The pattern excludes newlines, semicolons, and `)`
    // outside the matched parens to avoid spanning unrelated statements.
    re: /\.map\s*\((?:[^()\n;]|\([^()\n]*\))*\)\s*\.join\s*\(\s*["']-["']\s*\)/g,
    why: "phonetic-value .map(...).join('-') chain — use extractKnownPdSegments({ valueMap }) or buildPdBigramsFromWords({ valueMap }) instead",
  },
];

// Which canonical helpers signal a safe bigram pipeline. A function
// using either of these is presumed compliant.
const CANONICAL_HELPERS = [
  "buildPdBigramsFromWords",
  "extractKnownPdSegments",
];

function lineColFromOffset(text, offset) {
  let line = 1, col = 1;
  for (let i = 0; i < offset; i++) {
    if (text[i] === "\n") { line++; col = 1; }
    else col++;
  }
  return { line, col };
}

// Strip `// ...` line comments and `/* ... */` block comments while
// preserving newlines so line numbers stay accurate. We do NOT try to
// be a full lexer — the engine doesn't put `//` inside string literals
// in patterns we care about — but the substitutions are conservative.
function stripComments(text) {
  let out = text.replace(/\/\*[\s\S]*?\*\//g, (m) => m.replace(/[^\n]/g, " "));
  out = out.split("\n").map((line) => {
    const idx = line.indexOf("//");
    if (idx === -1) return line;
    return line.slice(0, idx) + " ".repeat(line.length - idx);
  }).join("\n");
  return out;
}

// Inline allowlist marker: a comment of the form
//   /* canonical-pipeline-allowed: <reason> */
// appearing on the same line as a banned pattern silences that one
// finding. Reasons must be present so reviewers can audit them.
const ALLOWLIST_RE = /\/\*\s*canonical-pipeline-allowed:[^*]*\*\//;

function scanFile(path) {
  const rawText = readFileSync(path, "utf8");
  const codeText = stripComments(rawText);
  const rawLines = rawText.split("\n");
  const findings = [];
  for (const { re, why } of BANNED_PATTERNS) {
    re.lastIndex = 0;
    let m;
    while ((m = re.exec(codeText)) !== null) {
      const { line, col } = lineColFromOffset(codeText, m.index);
      if (ALLOWLIST_RE.test(rawLines[line - 1] ?? "")) continue;
      findings.push({ line, col, snippet: m[0], why });
    }
  }
  return { rawText, findings };
}

function main() {
  console.log(`verify-engine-invariants: scanning ${SCAN_PATHS.length} files\n`);
  let totalFindings = 0;
  for (const path of SCAN_PATHS) {
    const display = relative(REPO_ROOT, path).replace(/\\/g, "/");
    const { findings } = scanFile(path);
    for (const f of findings) {
      console.log(`FAIL  ${display}:${f.line}:${f.col}  banned pattern: ${f.snippet}`);
      console.log(`      ${f.why}`);
    }
    totalFindings += findings.length;
  }

  // Sanity: the canonical helpers themselves must still exist. Any
  // refactor that renames or deletes them must update this list.
  const engineText = readFileSync(ENGINE_PATH, "utf8");
  const missingHelpers = CANONICAL_HELPERS.filter((h) => !new RegExp(`function ${h}\\b`).test(engineText));
  for (const h of missingHelpers) {
    console.log(`FAIL  canonical helper '${h}' is missing from comparison.mjs`);
  }

  if (totalFindings === 0 && missingHelpers.length === 0) {
    console.log(`PASS  no banned bigram-pipeline patterns found across ${SCAN_PATHS.length} files`);
    console.log(`PASS  canonical helpers present: ${CANONICAL_HELPERS.join(", ")}`);
    process.exit(0);
  }
  console.log("\nverify-engine-invariants: FAILED");
  console.log("Hint: every disc-bigram-producing path must call one of:");
  for (const h of CANONICAL_HELPERS) console.log(`  - ${h}(...)`);
  process.exit(1);
}

main();
